    public synchronized int get(int key) {
        if (!map.containsKey(key)) return -1;
        Node node = map.get(key);
        moveToHead(node);
        return node.value;
    }

    public synchronized void put(int key, int value) {
        if (map.containsKey(key)) {
            Node node = map.get(key);
            node.value = value;
            moveToHead(node);
        } else {
            if (map.size() >= capacity) {
                map.remove(tail.key);
                removeNode(tail);
            }
            Node newNode = new Node();
            newNode.key = key;
            newNode.value = value;
            addNode(newNode);
            map.put(key, newNode);
        }
