public class ChatGateway {
    private Map<String, UserConnection> activeConnections = new ConcurrentHashMap<>();
    private Map<String, Queue<Message>> offlineQueues = new ConcurrentHashMap<>();

    public void sendMessage(Message msg) {
        if (activeConnections.containsKey(msg.getRecipientId())) {
            activeConnections.get(msg.getRecipientId()).send(msg);
            msg.setStatus(MessageStatus.DELIVERED);
        } else {
            offlineQueues.computeIfAbsent(msg.getRecipientId(), k -> new ConcurrentLinkedQueue<>()).add(msg);
        }
    }
}

